import React, { useState, useMemo } from 'react';
import { Award, Play, Bookmark, X } from 'lucide-react';
import CourseCard from './components/CourseCard.jsx';
import { CourseCardSkeleton } from './components/LoadingSpinner.jsx';
import UnifiedSearch from './components/UnifiedSearch.jsx';
import QuickStats from './components/QuickStats.jsx';
import PaymentModal from './components/PaymentModal.jsx';
import { sortCourses } from './utils/courseUtils';
import useCourseStore from './store/courseStore';
import useAuthStore from './store/authStore';
import { useToast } from './components/Toast.jsx';

const Course = ({ courses }) => {
  const { showToast } = useToast();
  const { enrollInCourse } = useCourseStore();
  const { user } = useAuthStore();

  const [selectedCourse, setSelectedCourse] = useState(null);
  const [paymentCourse, setPaymentCourse] = useState(null);
  const [viewMode, setViewMode] = useState('grid');
  const [searchTerm, setSearchTerm] = useState('');
  const [filters, setFilters] = useState({ category: 'all', priceRange: [0, 200], rating: 0 });
  const [sortBy, setSortBy] = useState('rating');

  const filteredCourses = useMemo(() => {
    let filtered = courses.filter(course => {
      const matchesSearch = !searchTerm || course.title.toLowerCase().includes(searchTerm.toLowerCase()) || course.instructor.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = filters.category === 'all' || course.cat === filters.category;
      const matchesPrice = course.price >= filters.priceRange[0] && course.price <= filters.priceRange[1];
      const matchesRating = parseFloat(course.rating) >= filters.rating;
      return matchesSearch && matchesCategory && matchesPrice && matchesRating;
    });
    return sortCourses(filtered, sortBy);
  }, [courses, searchTerm, filters, sortBy]);

  const handleEnroll = (course) => {
    const { enrolledCourses } = useCourseStore.getState();
    if (enrolledCourses.includes(course.id)) {
      showToast('Already enrolled in this course', 'info');
      return;
    }
    setPaymentCourse(course);
  };

  const handlePaymentSuccess = (course, email) => {
    enrollInCourse(course.id);
    showToast(`Enrolled in ${course.title}!`, 'success');
    setTimeout(() => showToast(`Confirmation sent to ${email}`, 'info'), 1000);
  };

  const Modal = ({ course, onClose }) => (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto shadow-2xl">
        <div className="relative">
          <img className="w-full h-64 object-cover" src={course.img} alt={course.title} />
          <button onClick={onClose} className="absolute top-4 right-4 bg-white/90 text-gray-700 w-10 h-10 rounded-full flex items-center justify-center hover:bg-white">
            <X className="w-5 h-5" />
          </button>
        </div>
        <div className="p-8">
          <div className="flex justify-between items-start mb-4">
            <h2 className="text-2xl font-bold text-gray-900">{course.title}</h2>
            <span className="text-2xl font-bold text-blue-600">₹{course.price.toLocaleString()}</span>
          </div>
          <p className="text-gray-600 mb-6">{course.desc}</p>
          <div className="grid grid-cols-2 gap-4 mb-6">
            {[
              ['Instructor', course.instructor],
              ['Duration', course.time],
              ['Level', course.level],
              ['Students', course.enrolled.toLocaleString()]
            ].map(([label, value]) => (
              <div key={label} className="bg-gray-50 p-4 rounded-lg">
                <div className="text-gray-500 text-sm">{label}</div>
                <div className="font-semibold text-gray-900">{value}</div>
              </div>
            ))}
          </div>
          <div className="flex space-x-4">
            <button className="flex-1 bg-green-600 hover:bg-green-700 text-white font-semibold py-3 px-6 rounded-lg transition">
              <Play className="w-4 h-4 inline mr-2" />Preview
            </button>
            <button className="bg-gray-100 hover:bg-gray-200 text-gray-700 px-6 py-3 rounded-lg transition">
              <Bookmark className="w-4 h-4" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <section className="pt-16 pb-16 bg-gradient-to-br from-blue-50 via-white to-purple-50">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <div className="inline-flex items-center bg-blue-100 text-blue-700 px-4 py-2 rounded-full text-sm font-medium mb-4">
            <Award className="w-4 h-4 mr-2" />#1 Learning Platform
          </div>
          <h1 className="text-4xl sm:text-6xl font-bold mb-6 text-gray-900">
            {user?.role === 'instructor' ? (
              <>Teach & <span className="bg-gradient-to-r from-purple-600 to-pink-600 bg-clip-text text-transparent">Inspire</span></>
            ) : (
              <>Learn Without <span className="bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">Limits</span></>
            )}
          </h1>
          <p className="text-xl mb-8 text-gray-600 max-w-3xl mx-auto">
            {user?.role === 'instructor' 
              ? `Share your expertise with ${courses.length} courses and help students achieve their goals.`
              : `Start, switch, or advance your career with ${courses.length} courses from world-class instructors.`
            }
          </p>
          <QuickStats courses={courses} />
          <div className="flex flex-col sm:flex-row items-center justify-center gap-4 mt-8">
            <button className={`${user?.role === 'instructor' ? 'bg-gradient-to-r from-purple-600 to-pink-600 hover:from-purple-700 hover:to-pink-700' : 'bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700'} text-white px-8 py-4 rounded-xl font-semibold text-lg transition-all transform hover:scale-105 shadow-lg`}>
              {user?.role === 'instructor' ? 'Create Your First Course' : 'Start Learning Today'}
            </button>
          </div>
        </div>
      </section>

      {/* Search & Filters */}
      <UnifiedSearch onSearch={setSearchTerm} onFilter={setFilters} onSort={setSortBy} onViewChange={setViewMode} viewMode={viewMode} />

      {/* Course Grid */}
      <div className="max-w-7xl mx-auto px-4 py-12">
        {filteredCourses.length > 0 ? (
          <div className={viewMode === 'grid' ? 'grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6' : 'space-y-6'}>
            {filteredCourses.map(course => (
              <CourseCard key={course.id} course={course} viewMode={viewMode} onEnroll={handleEnroll} onPreview={setSelectedCourse} />
            ))}
          </div>
        ) : (
          <div className="text-center py-16">
            <div className="w-24 h-24 mx-auto mb-6 bg-gray-100 rounded-full flex items-center justify-center">
              <Award className="w-12 h-12 text-gray-400" />
            </div>
            <h3 className="text-xl font-semibold text-gray-900 mb-2">No courses found</h3>
            <p className="text-gray-600">Try adjusting your search or filters</p>
          </div>
        )}
      </div>

      {selectedCourse && <Modal course={selectedCourse} onClose={() => setSelectedCourse(null)} />}
      {paymentCourse && <PaymentModal course={paymentCourse} onClose={() => setPaymentCourse(null)} onPaymentSuccess={handlePaymentSuccess} />}
    </div>
  );
};

export default Course;
